SELECT

id,

create_time, update_time,

organ_name, organ_type, status, admin,

delete_flag,

version
FROM organ




        AND id = #{id, jdbcType=BIGINT}


        AND id IN

            #{item, jdbcType=BIGINT}





            AND create_time >= #{createTime[0], jdbcType=TIMESTAMP}


            AND create_time <= #{createTime[1], jdbcType=TIMESTAMP}


            AND create_time BETWEEN #{createTime[0], jdbcType=TIMESTAMP}
            AND #{createTime[1], jdbcType=TIMESTAMP}




            AND update_time >= #{updateTime[0], jdbcType=TIMESTAMP}


            AND update_time <= #{updateTime[1], jdbcType=TIMESTAMP}


            AND update_time BETWEEN #{updateTime[0], jdbcType=TIMESTAMP}
            AND #{updateTime[1], jdbcType=TIMESTAMP}




        AND organ_name = #{organName, jdbcType=VARCHAR}


        AND organ_type = #{organType, jdbcType=VARCHAR}


        AND status = #{status, jdbcType=VARCHAR}


        AND admin = #{admin, jdbcType=TINYINT}


    AND (delete_flag = 0 OR delete_flag IS NULL)

SELECT DISTINCT o.id, o.create_time, o.update_time, o.organ_name, o.organ_type, o.status, o.admin,
o.delete_flag, o.version
FROM organ o
INNER JOIN organ_closure oc ON o.id = oc.descendant_id


    o.delete_flag = 0 AND oc.delete_flag = 0




            AND oc.ancestor_id = #{organId, jdbcType=BIGINT}


            AND oc.relation_type = 'SELF_ASSOCIATION'





        AND o.id = #{id, jdbcType=BIGINT}


        AND o.id IN

            #{item, jdbcType=BIGINT}





            AND o.create_time >= #{createTime[0], jdbcType=TIMESTAMP}


            AND o.create_time <= #{createTime[1], jdbcType=TIMESTAMP}


            AND o.create_time BETWEEN #{createTime[0], jdbcType=TIMESTAMP}
            AND #{createTime[1], jdbcType=TIMESTAMP}




            AND o.update_time >= #{updateTime[0], jdbcType=TIMESTAMP}


            AND o.update_time <= #{updateTime[1], jdbcType=TIMESTAMP}


            AND o.update_time BETWEEN #{updateTime[0], jdbcType=TIMESTAMP}
            AND #{updateTime[1], jdbcType=TIMESTAMP}




        AND o.organ_name LIKE CONCAT('%', #{organName, jdbcType=VARCHAR}, '%')


        AND o.organ_type = #{organType, jdbcType=VARCHAR}


        AND o.status = #{status, jdbcType=VARCHAR}


        AND o.admin = #{admin, jdbcType=TINYINT}







                o.id



                o.create_time



